import{_ as e,o as a,c as r,a7 as i}from"./chunks/framework.C5fSpjcB.js";const g=JSON.parse('{"title":"Investigation","description":"","frontmatter":{},"headers":[],"relativePath":"en/modes/investigation.md","filePath":"en/modes/investigation.md","lastUpdated":1775394001000}'),s={name:"en/modes/investigation.md"};function o(d,t,n,l,h,c){return a(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="investigation" tabindex="-1">Investigation <a class="header-anchor" href="#investigation" aria-label="Permalink to &quot;Investigation&quot;">​</a></h1><p><strong>Investigation</strong> is Morimens&#39; roguelite exploration mode. Players navigate a hex-based map, encountering enemies, events, and rewards as they progress through procedurally arranged stages.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aspect</th><th>Detail</th></tr></thead><tbody><tr><td>Mode Type</td><td>Roguelite PvE</td></tr><tr><td>Map</td><td>Hex-tile grid</td></tr><tr><td>Progression</td><td>Procedural; each run is different</td></tr><tr><td>Rewards</td><td>Cards, materials, Engravings, currency</td></tr></tbody></table><h2 id="how-investigation-works" tabindex="-1">How Investigation Works <a class="header-anchor" href="#how-investigation-works" aria-label="Permalink to &quot;How Investigation Works&quot;">​</a></h2><ol><li><strong>Enter a run</strong> -- Select your team of up to 4 Awakeners.</li><li><strong>Navigate the hex map</strong> -- Move tile by tile, choosing your path.</li><li><strong>Encounter tile events</strong> -- Each tile has an event type (combat, treasure, shop, etc.).</li><li><strong>Build your deck</strong> -- Acquire new cards during the run to strengthen your deck.</li><li><strong>Reach the boss</strong> -- Defeat the final encounter to complete the Investigation.</li></ol><h2 id="tile-types" tabindex="-1">Tile Types <a class="header-anchor" href="#tile-types" aria-label="Permalink to &quot;Tile Types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tile</th><th>Icon</th><th>Description</th></tr></thead><tbody><tr><td>Combat</td><td>Sword</td><td>Battle enemies; rewards cards and materials</td></tr><tr><td>Elite Combat</td><td>Red Sword</td><td>Harder fight; better rewards</td></tr><tr><td>Treasure</td><td>Chest</td><td>Free item or card reward</td></tr><tr><td>Shop</td><td>Coin</td><td>Spend currency earned during the run to buy cards or items</td></tr><tr><td>Event</td><td>Question Mark</td><td>Random event with choices; can be beneficial or risky</td></tr><tr><td>Rest</td><td>Campfire</td><td>Heal your team or upgrade a card</td></tr><tr><td>Boss</td><td>Skull</td><td>Final encounter of the Investigation</td></tr></tbody></table><h2 id="stage-assists" tabindex="-1">Stage Assists <a class="header-anchor" href="#stage-assists" aria-label="Permalink to &quot;Stage Assists&quot;">​</a></h2><p>During Investigation, <strong>Stage Assists</strong> provide temporary buffs or effects that last for the duration of the run:</p><ul><li>Stage Assists are offered at certain checkpoints.</li><li>Choose from a selection of assists to complement your team and deck strategy.</li><li>Assists do not carry over between runs.</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The rest tile choice between healing and upgrading a card is important. If your HP is healthy, always choose the card upgrade -- permanent power increases are more valuable than temporary healing.</p></div><h2 id="deckbuilding-during-investigation" tabindex="-1">Deckbuilding During Investigation <a class="header-anchor" href="#deckbuilding-during-investigation" aria-label="Permalink to &quot;Deckbuilding During Investigation&quot;">​</a></h2><p>Investigation is where your deckbuilding skills matter most:</p><ul><li>You start with your Awakeners&#39; base cards.</li><li>Acquire additional cards from combat rewards, treasure tiles, and shops.</li><li>Synergy matters -- pick cards that complement your realm strategy rather than taking every card offered.</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Adding too many cards to your deck dilutes your draw pool. Be selective; sometimes skipping a card reward is the correct choice.</p></div><h2 id="rewards" tabindex="-1">Rewards <a class="header-anchor" href="#rewards" aria-label="Permalink to &quot;Rewards&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Reward Type</th><th>Source</th></tr></thead><tbody><tr><td>Cards</td><td>Combat tiles, treasure tiles</td></tr><tr><td>Materials</td><td>Combat tiles, completion bonus</td></tr><tr><td>Engravings</td><td>Elite combat, boss</td></tr><tr><td>Currency</td><td>Various tiles</td></tr></tbody></table><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./combat.html">Combat System</a></li><li><a href="./../cards/deckbuilding.html">Deckbuilding Guide</a></li><li><a href="./../engravings/">Engravings</a></li><li><a href="./../awakeners/team-building.html">Team Building</a></li></ul>',20)])])}const m=e(s,[["render",o]]);export{g as __pageData,m as default};
